    wp_errors: list[str] = []
    all_events: list[StatusEvent] = []

    for wp_file in wp_files:
        try:
            frontmatter, _body = read_frontmatter(wp_file)
        except Exception as exc:
            logger.warning("Failed to read frontmatter from %s: %s", wp_file, exc)
